def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    # We'll compare the original and modified slide
    original = Presentation(original_ppt_path)
    modified = Presentation(modified_ppt_path)
    if len(original.slides) < 10 or len(modified.slides) < 10:
        return ("One of the presentations has fewer than 10 slides.", 0.0)
    orig_slide = original.slides[9]
    mod_slide = modified.slides[9]
    # Count text-containing placeholders (main content, title, etc.)
    orig_texts = []
    for shape in orig_slide.shapes:
        if shape.has_text_frame:
            orig_texts.append(shape.text_frame.text.strip())
    mod_texts = []
    for shape in mod_slide.shapes:
        if shape.has_text_frame:
            mod_texts.append(shape.text_frame.text.strip())
    # Find the new text
    new_texts = [t for t in mod_texts if t not in orig_texts]
    if not new_texts:
        return ("No new text detected on Slide 10.", 0.0)
    # Check if the new text appears in a shape that originally contained bullet points (main content)
    for shape in mod_slide.shapes:
        if not shape.has_text_frame:
            continue
        # Find the corresponding shape in the original slide to check its content
        original_shape_text = ""
        for o_shape in orig_slide.shapes:
            # A simple heuristic to match shapes is by shape_id, assuming it's consistent
            if o_shape.shape_id == shape.shape_id and o_shape.has_text_frame:
                original_shape_text = o_shape.text_frame.text.strip()
                break

        # If this shape had content originally that contained 'object' or 'objects', it's the target box
        if 'object' in original_shape_text.lower() or 'objects' in original_shape_text.lower():
            mod_paras = [p.text.strip() for p in shape.text_frame.paragraphs if p.text.strip()]

            new_bullet_text = "Objects include CSS files, JavaScript files, images, videos"

            try:
                # Find the 1-based index of the new bullet point
                position = mod_paras.index(new_bullet_text) + 1

                if position == 4:
                    return ("New bullet point is in the 4th position.", 1.0)
                elif position in [2, 3]:
                    return (f"New bullet point is in position {position}, not 4th.", 0.7)
                else:
                    return (f"New bullet point is in the main text box but at the wrong position ({position}).", 0.5)
            except ValueError:
                # The new bullet point text is not found as a whole paragraph.
                # This can happen if it's merged with another, or not added correctly.
                # We can check if any of the new text is present.
                orig_paras_text = [p.text.strip() for p in o_shape.text_frame.paragraphs if p.text.strip()]
                added_paras = [p for p in mod_paras if p not in orig_paras_text]
                if added_paras:
                     return ("New content added to the main text box, but not as the specified bullet point or in the correct format.", 0.5)

    return ("Bullet point not placed in a semantically appropriate location.", 0.0)

